function extractLinkToken(text: string): string | null {
  const normalized = text.trim().replace(/\s+/g, " ");
  if (!normalized) return null;
  const prefix = (process.env.ZALO_LINK_MESSAGE_PREFIX || "LINK").trim();
  const prefixed = new RegExp(`^${prefix.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\s+(.+)$`, "i").exec(normalized);
  return (prefixed?.[1] ?? normalized).trim() || null;
}

